style.sankey-chart-base$:
{% set pv = states('__solar_energy_today__') | float(0) %}
{% set bat_d = states('__battery_discharge_today__') | float(0) %}
{% set grid_i = states('__grid_import_today__') | float(0) %}
{% set bat_c = states('__battery_charge_today__') | float(0) %}
{% set load = states('__load_energy_today__') | float(0) %}
{% set grid_e = states('__grid_export_today__') | float(0) %}
{% set src = pv + bat_d + grid_i %}
{% set dst = bat_c + load + grid_e %}
:host {
  --pct-src-solar: "{{ '%0.2f' | format((pv/src*100) if src > 0 else 0) }}%";
  --pct-src-bat: "{{ '%0.2f' | format((bat_d/src*100) if src > 0 else 0) }}%";
  --pct-src-grid: "{{ '%0.2f' | format((grid_i/src*100) if src > 0 else 0) }}%";
  --pct-dst-bat: "{{ '%0.2f' | format((bat_c/dst*100) if dst > 0 else 0) }}%";
  --pct-dst-load: "{{ '%0.2f' | format((load/dst*100) if dst > 0 else 0) }}%";
  --pct-dst-grid: "{{ '%0.2f' | format((grid_e/dst*100) if dst > 0 else 0) }}%";
}
ha-card {
  --ha-card-background: transparent !important; --card-background-color: transparent !important;
  border: none !important;
  border-radius: 4px !important;
  overflow: hidden !important;
  padding: 2px !important;
  max-width: 100% !important;
}
path[fill-opacity] {
  fill-opacity: 0.55 !important;
}
.container, .section {
  overflow: visible !important;
}

.box {
  overflow: hidden !important;
  position: relative !important;
}
/* Source side: wide bars */
.section:first-of-type .box > div:first-child {
  min-width: 90px !important;
  border-radius: 8px 0 0 8px !important;
}
/* Destination side: reverse flex, bar at right edge */

.section:last-of-type .box > div:first-child {
  min-width: 90px !important;
  border-radius: 0 8px 8px 0 !important;
}
/* Labels: positioned top-to-bottom inside bar */
.box .label {
  position: absolute !important;
  top: 2px !important;
  bottom: 2px !important;
  transform: none !important;
  display: flex !important;
  flex-direction: column !important;
  justify-content: flex-start !important;
  gap: 0px !important;
  line-height: normal !important;
  z-index: 2 !important;
  width: auto !important;
  max-width: 160px !important;
  overflow: visible !important;
  padding: 0 6px !important;
  background: transparent !important;
  margin: 0 !important;
}
/* Source labels: left-aligned */
.section:first-of-type .box .label {
  left: 6px !important;
  align-items: flex-start !important;
  text-align: left !important;
}
/* Destination labels: right-aligned */
.section:last-of-type .box .label {
  right: 6px !important;
  align-items: flex-end !important;
  text-align: right !important;
}
/* Name pill badge */
.box .label .name {
  order: -2 !important;
  background: rgba(0,0,0,0.45) !important;
  border: 1.5px solid rgba(255,255,255,0.3) !important;
  border-radius: 10px !important;
  padding: 1px 8px !important;
  font-size: 7.5px !important;
  font-weight: 700 !important;
  letter-spacing: 1px !important;
  text-transform: uppercase !important;
  margin-bottom: 2px !important;
  white-space: nowrap !important;
  color: #fff !important;
  width: fit-content !important;
}
/* Color-coded pill borders */
.box > div[title*="Solar"] ~ .label .name { border-color: #c8b84a !important; }
.box > div[title*="Battery"] ~ .label .name { border-color: #00d4b8 !important; }
.section:first-of-type .box > div[title*="Grid"] ~ .label .name { border-color: #6b7fd4 !important; }
.section:last-of-type .box > div[title*="Grid"] ~ .label .name { border-color: #7c5cbf !important; }
.box > div[title*="Load"] ~ .label .name { border-color: #e8337f !important; }
/* State value container */
.box .label > span:first-child {
  order: -1 !important;
  display: flex !important;
  flex-direction: column !important;
}
.box {
  min-height: 30px !important;
}
.box .label .state {
  font-size: 22px !important;
  font-weight: 800 !important;
  color: #fff !important;
  line-height: 1.1 !important;
  text-shadow: 0 1px 4px rgba(0,0,0,0.7) !important;
}
.box .label .unit {
  font-size: 10px !important;
  font-weight: 500 !important;
  color: rgba(255,255,255,0.65) !important;
  text-shadow: 0 1px 2px rgba(0,0,0,0.5) !important;
}
/* Percentage labels - pushed to bottom */
.box .label::after {
  font-size: 9px !important;
  font-weight: 600 !important;
  color: rgba(255,255,255,0.55) !important;
  margin-top: auto !important;
  text-shadow: 0 1px 2px rgba(0,0,0,0.5) !important;
  white-space: nowrap !important;
}
/* Source percentages */
.section:first-of-type .box > div[title*="Solar"] ~ .label::after { content: var(--pct-src-solar); }
.section:first-of-type .box > div[title*="Battery"] ~ .label::after { content: var(--pct-src-bat); }
.section:first-of-type .box > div[title*="Grid"] ~ .label::after { content: var(--pct-src-grid); }
/* Destination percentages */
.section:last-of-type .box > div[title*="Battery"] ~ .label::after { content: var(--pct-dst-bat); }
.section:last-of-type .box > div[title*="Load"] ~ .label::after { content: var(--pct-dst-load); }
.section:last-of-type .box > div[title*="Grid"] ~ .label::after { content: var(--pct-dst-grid); }
/* Mobile-responsive sankey */
@media (max-width: 800px) {
  .section:first-of-type .box > div:first-child { min-width: 65px !important; }
  .section:last-of-type .box > div:first-child { min-width: 65px !important; }

  .box .label .state { font-size: 16px !important; }
  .box .label .name { font-size: 6px !important; padding: 0 4px !important; }
  .box .label .unit { font-size: 8px !important; }
  .box .label::after { font-size: 7px !important; }
}

