/* Sankey layout fix */
.section:first-of-type { flex: 1 1 auto !important; max-width: none !important; }
.section:last-of-type { flex: 0 0 auto !important; width: auto !important; max-width: none !important; position: relative !important; z-index: 2 !important; }
.section:last-of-type .box { flex-direction: row-reverse !important; }
.connectors { left: 90px !important; width: calc(100% - 88px) !important; overflow: visible !important; z-index: 1 !important; }
.connectors svg { width: 100% !important; left: 0 !important; overflow: visible !important; }
@media (max-width: 800px) { .connectors { left: 65px !important; width: calc(100% - 63px) !important; } }

